import styles from "./page.module.css"
import Reserve from "@/components/reservation/Reserve"


export default function page() {
    return (
        <section className={styles.section}>
            {/*<Location />*/}
            <Reserve />
            <Info />
            <button type={"reset"} className={styles.button}>새로 고침</button>
            <button type={"submit"} className={styles.button}>다음 단계</button>
        </section>
    )
}

function Info() {
    return (
        <div className={styles.info}>
            <h3>예약 선택</h3>
            <div>
                <input type={"checkbox"} id={"opt1"} name={"opt1"} value={"임시1"}/>
                <label htmlFor={"opt1"}> 옵션 1</label>
            </div>
        </div>
    )
}

